const Header = (props) => {
  return (
    <div>
      <p>
        {props.course.course.name}
      </p>
    </div>
  )
}

const Part = (props) => {
  console.log(props)
  return (
    <div>
      <p>
        {props.part} {props.exercise}
      </p> 
    </div>
  )
}

const Content = (content) => {
  console.log(content)
  return (
    <div>
      {content.map(part => <li
        key = {part.id}>
          {part.name}
        </li> )}
    </div>
  )
}


const Course = (course) => {
  return (
    <div>
      <Header course = {course}/>
      <ul>
        <Content content = {course.course.parts}/>
      </ul>
    </div>
  )
}




